//Copyright(c)HashiCorp,Inc.//SPDX-License-Identifier:MPL-2.0packagecloudhsmv2import("context""github.com/aws/aws-sdk-go/aws""github.com/aws/aws-sdk-go/service/cloudhsmv2""github.com/hashicorp/terraform-plugin-sdk/v2/helper/retry""github.com/hashicorp/terraform-provider-aws/internal/tfresource")funcFindClusterByID(ctxcontext.Context,conn*cloudhsmv2.CloudHSMV2,idstring)(*cloudhsmv2.Cluster,error){input:=&cloudhsmv2.DescribeClustersInput{Filters:map[string][]*string{"clusterIds":aws.StringSlice([]string{id}),},}output,err:=findCluster(ctx,conn,input)iferr!=nil{returnnil,err}ifstate:=aws.StringValue(output.State);state==cloudhsmv2.ClusterStateDeleted{returnnil,&retry.NotFoundError{Message:state,LastRequest:input,}}//Eventualconsistencycheck.ifaws.StringValue(output.ClusterId)!=id{returnnil,&retry.NotFoundError{LastRequest:input,}}returnoutput,nil}funcfindCluster(ctxcontext.Context,conn*cloudhsmv2.CloudHSMV2,input*cloudhsmv2.DescribeClustersInput)(*cloudhsmv2.Cluster,error){output,err:=findClusters(ctx,conn,input)iferr!=nil{returnnil,err}iflen(output)==0||output[0]==nil{returnnil,tfresource.NewEmptyResultError(input)}ifcount:=len(output);count>1{returnnil,tfresource.NewTooManyResultsError(count,input)}returnoutput[0],nil}funcfindClusters(ctxcontext.Context,conn*cloudhsmv2.CloudHSMV2,input*cloudhsmv2.DescribeClustersInput)([]*cloudhsmv2.Cluster,error){varoutput[]*cloudhsmv2.Clustererr:=conn.DescribeClustersPagesWithContext(ctx,input,func(page*cloudhsmv2.DescribeClustersOutput,lastPagebool)bool{ifpage==nil{return!lastPage}for_,v:=rangepage.Clusters{ifv!=nil{output=append(output,v)}}return!lastPage})iferr!=nil{returnnil,err}returnoutput,nil}funcFindHSMByTwoPartKey(ctxcontext.Context,conn*cloudhsmv2.CloudHSMV2,hsmID,eniIDstring)(*cloudhsmv2.Hsm,error){input:=&cloudhsmv2.DescribeClustersInput{}output,err:=findClusters(ctx,conn,input)iferr!=nil{returnnil,err}for_,v:=rangeoutput{for_,v:=rangev.Hsms{ifv==nil{continue}//CloudHSMv2HSMinstancescanberecreated,buttheENIIDwill//remainconsistent.WithoutthisENImatching,HSMinstances//instancescanbecomeorphaned.ifaws.StringValue(v.HsmId)==hsmID||aws.StringValue(v.EniId)==eniID{returnv,nil}}}returnnil,&retry.NotFoundError{}}